     7→const ONLINE_THRESHOLD_MS = 3 * 60 * 1000;
     8→
     9→function deriveStatus(lastSeenAt: Date | null): 'online' | 'offline' {
    10→  if (!lastSeenAt) return 'offline';
    11→  return (Date.now() - lastSeenAt.getTime()) < ONLINE_THRESHOLD_MS ? 'online' : 'offline';
    12→}
    13→
    14→const MSK = 'Europe/Moscow';
    15→
    16→function toMskTime(date: Date): string {
    17→  return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit', timeZone: MSK });
    18→}
    19→
    20→function toMskDate(date: Date): string {
    21→  return date.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short', timeZone: MSK });
    22→}
    23→
    24→function formatLastSeen(lastSeenAt: Date | null): string {
    25→  if (!lastSeenAt) return 'Не в сети';
    26→  const diffMs = Date.now() - lastSeenAt.getTime();
    27→  if (diffMs < 0) return 'Не в сети';
    28→  if (diffMs < ONLINE_THRESHOLD_MS) return 'В сети';
    29→  const diffMin = Math.floor(diffMs / 60_000);
    30→  if (diffMin < 60) return `${diffMin} мин назад`;
    31→  const diffH = Math.floor(diffMin / 60);
    32→  if (diffH < 24) return `был(а) в ${toMskTime(lastSeenAt)} МСК`;
    33→  const diffD = Math.floor(diffH / 24);
    34→  if (diffD === 1) return `вчера в ${toMskTime(lastSeenAt)} МСК`;
    35→  if (diffD < 7) return `${diffD} дня назад в ${toMskTime(lastSeenAt)} МСК`;
    36→  return `${toMskDate(lastSeenAt)} в ${toMskTime(lastSeenAt)} МСК`;
    37→}
    38→
    39→function mapRow(row: any) {
    40→  const lastSeenAt: Date | null = row.last_seen_at ? new Date(row.last_seen_at) : null;
    41→  const status = deriveStatus(lastSeenAt);
    42→  return {
    43→    id: row.id ? Number(row.id) : undefined,
    44→    name: row.name,
    45→    role: row.role,
    46→    pin: row.pin,
    47→    department: row.department,
    48→    status,
    49→    lastActive: formatLastSeen(lastSeenAt),
    50→  };
    51→}
