    10→function checkRateLimit(ip: string): boolean {
    11→  const now = Date.now();
    12→  const entry = attempts.get(ip);
    13→  if (!entry || entry.resetAt < now) {
    14→    attempts.set(ip, { count: 1, resetAt: now + 60_000 });
    15→    return true;
    16→  }
    17→  if (entry.count >= 10) return false;
    18→  entry.count++;
    19→  return true;
    20→}
