     3→export class ApiError extends Error {
     4→  constructor(public status: number, message: string) {
     5→    super(message);
     6→    this.name = 'ApiError';
     7→  }
     8→}
     9→
    10→async function request<T>(url: string, options?: RequestInit): Promise<T> {
    11→  const res = await fetch(url, {
    12→    headers: { 'Content-Type': 'application/json', ...options?.headers },
    13→    ...options,
    14→  });
    15→  if (!res.ok) {
    16→    let message = res.statusText;
    17→    try { message = (await res.json()).error || message; } catch { /* ignore */ }
    18→    throw new ApiError(res.status, message);
    19→  }
    20→  return res.json() as Promise<T>;
    21→}
